return [
  {
    json: {
      request_id: 'REQ-001',
      source: 'Email',
      received_at: '2026-03-13T09:15:00Z',
      customer_message: 'Hi, I tried logging in this morning and keep getting a 403 error. My account is arcvault.io/user/jsmith. This started after your update last Tuesday.'
    }
  },
  {
    json: {
      request_id: 'REQ-002',
      source: 'Web Form',
      received_at: '2026-03-13T09:18:00Z',
      customer_message: "We'd love to see a bulk export feature for our audit logs. We're a compliance-heavy org and this would save us hours every month."
    }
  },
  {
    json: {
      request_id: 'REQ-003',
      source: 'Support Portal',
      received_at: '2026-03-13T09:22:00Z',
      customer_message: 'Invoice #8821 shows a charge of $1,240 but our contract rate is $980/month. Can someone look into this?'
    }
  },
  {
    json: {
      request_id: 'REQ-004',
      source: 'Email',
      received_at: '2026-03-13T09:27:00Z',
      customer_message: "I'm not sure if this is the right place to ask, but is there a way to set up SSO with Okta? We're evaluating switching our auth provider."
    }
  },
  {
    json: {
      request_id: 'REQ-005',
      source: 'Web Form',
      received_at: '2026-03-13T09:31:00Z',
      customer_message: 'Your dashboard stopped loading for us around 2pm EST. Checked our end — it\'s definitely on yours. Multiple users affected.'
    }
  },
  {
    json: {
      request_id: 'REQ-006',
      source: 'Email',
      received_at: '2026-03-13T09:36:00Z',
      customer_message: "I'm having trouble accessing some parts of the system after the update."
    }
  }
];

const body = $json.body ?? $json;
const requestId = body.request_id ?? `REQ-${Date.now()}`;
const source = body.source ?? 'Webhook';
const receivedAt = body.received_at ?? new Date().toISOString();
const customerMessage = body.customer_message ?? body.message ?? body.text ?? '';

return [{
  json: {
    request_id: requestId,
    source,
    received_at: receivedAt,
    customer_message: customerMessage,
    normalized_source: source.toLowerCase().replace(/\s+/g, '_')
  }
}];

const item = $json;
const systemPrompt = `You are an AI support triage assistant for ArcVault, a fictional B2B SaaS company. Read one inbound customer request and return strict JSON only. Classify into exactly one of: Bug Report, Feature Request, Billing Issue, Technical Question, Incident/Outage. Assign exactly one priority of Low, Medium, or High. Confidence must be a number from 0.00 to 1.00. Extract only identifiers clearly supported by the message. core_issue and urgency_signal must each be one sentence. summary must be 2 to 3 sentences. Omit unknown fields instead of fabricating them.`;
const userPrompt = `Request metadata:
- request_id: ${item.request_id}
- source: ${item.source}
- received_at: ${item.received_at}

Customer message:
${item.customer_message}`;
return [{ json: { ...item, llm_prompt: { system: systemPrompt, user: userPrompt }, llm_mode: 'mock' } }];

const text = $json.customer_message;
const lower = text.toLowerCase();

function result(payload) {
  return [{ json: { ...$json, llm_result: payload } }];
}

if (lower.includes('403 error')) {
  return result({
    category: 'Bug Report',
    priority: 'High',
    confidence: 0.96,
    core_issue: 'Customer login is failing with a 403 error after a recent product update.',
    relevant_identifiers: {
      account_path: 'arcvault.io/user/jsmith',
      error_code: '403',
      reported_start: 'this morning',
      change_reference: 'after your update last Tuesday'
    },
    urgency_signal: 'User blocked from core login workflow.',
    summary: 'A customer reported that login is failing with a 403 error for account arcvault.io/user/jsmith. The issue appears tied to a recent product update, so it should be reviewed by Engineering quickly.'
  });
}

if (lower.includes('bulk export feature')) {
  return result({
    category: 'Feature Request',
    priority: 'Low',
    confidence: 0.98,
    core_issue: 'Customer wants bulk export for audit logs to support recurring compliance workflows.',
    relevant_identifiers: {
      requested_capability: 'bulk export',
      product_area: 'audit logs',
      business_context: 'compliance-heavy organization'
    },
    urgency_signal: 'Time-saving request with recurring operational value, but no active service disruption.',
    summary: 'A customer asked for bulk export support for audit logs to reduce recurring compliance effort. This is a clear feature request with high confidence and should be routed to Product.'
  });
}

if (lower.includes('invoice #8821')) {
  return result({
    category: 'Billing Issue',
    priority: 'Medium',
    confidence: 0.99,
    core_issue: 'Customer believes invoice #8821 is overcharged relative to their contract rate.',
    relevant_identifiers: {
      invoice_number: '8821',
      billed_amount_usd: 1240,
      contract_rate_usd: 980,
      billing_difference_usd: 260
    },
    urgency_signal: 'Potential billing discrepancy with direct monetary impact.',
    summary: 'A customer flagged invoice #8821 as billed at $1,240 instead of their $980 contract rate. The issue belongs with Billing for review and does not cross the escalation threshold.'
  });
}

if (lower.includes('okta')) {
  return result({
    category: 'Technical Question',
    priority: 'Low',
    confidence: 0.95,
    core_issue: 'Customer is seeking guidance on whether ArcVault supports SSO integration with Okta.',
    relevant_identifiers: {
      identity_provider: 'Okta',
      topic: 'SSO setup',
      decision_context: 'evaluating switching auth provider'
    },
    urgency_signal: 'Pre-sales or implementation guidance request without service impact.',
    summary: 'A customer asked whether ArcVault can be configured for SSO with Okta as part of an auth-provider evaluation. This is a technical question and should be routed to IT/Security.'
  });
}

if (lower.includes('dashboard stopped loading')) {
  return result({
    category: 'Incident/Outage',
    priority: 'High',
    confidence: 0.99,
    core_issue: 'Customer reports a likely ArcVault-side dashboard outage affecting multiple users.',
    relevant_identifiers: {
      affected_product_area: 'dashboard',
      reported_time: 'around 2pm EST',
      affected_scope: 'multiple users',
      suspected_ownership: 'ArcVault'
    },
    urgency_signal: 'Multiple users impacted by a probable service outage.',
    summary: 'A customer reported that the dashboard stopped loading around 2pm EST and said multiple users are affected. This strongly suggests an ArcVault-side outage and should be escalated immediately.'
  });
}

if (lower.includes('trouble accessing some parts of the system after the update')) {
  return result({
    category: 'Technical Question',
    priority: 'Medium',
    confidence: 0.55,
    core_issue: 'Customer reports partial system access issues after an update, but the message is too ambiguous to classify more precisely.',
    relevant_identifiers: {
      change_reference: 'after the update',
      affected_scope: 'some parts of the system'
    },
    urgency_signal: 'Possible post-release issue, but the impact and failure mode are unclear from the message.',
    summary: 'A customer reported trouble accessing some parts of the system after an update, but did not provide enough detail to determine whether this is a bug, outage, or setup issue. It should be escalated for human review because the classification confidence is low.'
  });
}

return result({
  category: 'Technical Question',
  priority: 'Medium',
  confidence: 0.55,
  core_issue: 'The request could not be confidently classified from the available message content.',
  relevant_identifiers: {},
  urgency_signal: 'Message is ambiguous and requires manual review.',
  summary: 'The inbound request was too ambiguous for confident automated triage. It should be routed for human review.'
});

const categoryToQueue = {
  'Bug Report': 'Engineering',
  'Incident/Outage': 'Engineering',
  'Feature Request': 'Product',
  'Billing Issue': 'Billing',
  'Technical Question': 'IT/Security'
};

const llm = $json.llm_result;
const message = $json.customer_message.toLowerCase();
const reasons = [];
let queue = categoryToQueue[llm.category] ?? 'Escalation Queue';

if (llm.confidence < 0.7) {
  reasons.push('Confidence below 0.70.');
}
if (message.includes('outage') || message.includes('down') || message.includes('stopped loading')) {
  reasons.push('Message indicates outage/down condition.');
}
if (message.includes('multiple users affected')) {
  reasons.push('Multiple users affected.');
}
const billingDifference = llm.relevant_identifiers?.billing_difference_usd;
if (typeof billingDifference === 'number' && billingDifference > 500) {
  reasons.push('Billing discrepancy exceeds $500.');
}

const escalated = reasons.length > 0;
if (escalated) {
  queue = 'Escalation Queue';
}

return [{
  json: {
    ...$json,
    routing_decision: {
      queue,
      escalated,
      escalation_reasons: reasons
    }
  }
}];

const llm = $json.llm_result;
const identifiers = llm.relevant_identifiers ?? {};

let normalizedText = $json.customer_message;
if ($json.request_id === 'REQ-001') {
  normalizedText = 'Customer cannot log in and receives a 403 error. Account path: arcvault.io/user/jsmith. Issue began after last Tuesday\'s product update.';
} else if ($json.request_id === 'REQ-002') {
  normalizedText = 'Customer requests a bulk export capability for audit logs to reduce manual compliance work.';
} else if ($json.request_id === 'REQ-003') {
  normalizedText = 'Customer reports invoice #8821 is billed at $1,240 instead of the contracted $980 monthly rate.';
} else if ($json.request_id === 'REQ-004') {
  normalizedText = 'Customer asks whether ArcVault supports SSO setup with Okta while evaluating an authentication provider change.';
} else if ($json.request_id === 'REQ-005') {
  normalizedText = 'Customer reports the dashboard stopped loading around 2pm EST and says multiple users are affected, with the issue likely on ArcVault\'s side.';
} else if ($json.request_id === 'REQ-006') {
  normalizedText = 'Customer reports vague access trouble affecting some parts of the system after a product update, without naming a specific feature, error, or affected scope.';
}

return [{
  json: {
    request_id: $json.request_id,
    source: $json.source,
    received_at: $json.received_at,
    customer_message: $json.customer_message,
    normalized_text: normalizedText,
    classification: {
      category: llm.category,
      priority: llm.priority,
      confidence: llm.confidence
    },
    enrichment: {
      core_issue: llm.core_issue,
      relevant_identifiers: identifiers,
      urgency_signal: llm.urgency_signal
    },
    decision: $json.routing_decision,
    summary: llm.summary,
    processing_metadata: {
      workflow_version: '1.0.0',
      llm_mode: $json.llm_mode,
      model: 'placeholder-single-step-llm',
      processed_at: new Date().toISOString()
    }
  }
}];
